// // (1) reset_n: Resets the counter to 8'b11111111 when high.
// (2) enable: Disables the counter increment operation when high.
// (3) q: The value of the counter.
module top_module(
    input clk,
    input reset_n,
    input enable,
    output reg [7:0] q
);

    always @(posedge clk) begin
        if (!reset_n) begin
            // Synchronous reset: Reset the counter to 8'b00000000
            q <= 8'b00000000;
        end else if (enable) begin
            // Counter increment: Increment by 1 when enabled
            q <= q + 1;
        end
    end

endmodule

